/* ===== CREATE (multi-doc) ===== */
const Create=({onNav})=>{
  const [step,setStep]=useState(0);const steps=["Documents","Signataires","Champs","Options","Envoi"];
  return <div style={{flex:1,overflow:"auto"}}>
    <Hd title="Nouvelle enveloppe"><Bt v="outline" onClick={()=>onNav("dashboard")}>Annuler</Bt></Hd>
    <div style={{padding:"18px 32px"}}>
      <div style={{display:"flex",alignItems:"center",gap:0,marginBottom:24}}>{steps.map((s,i)=><div key={s} style={{display:"flex",alignItems:"center",flex:i<4?1:0}}><div style={{display:"flex",alignItems:"center",gap:6}}><div style={{width:26,height:26,borderRadius:13,background:i<=step?C.primary:C.bg,color:i<=step?"#fff":C.tm,display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:700,border:i<=step?"none":`1.5px solid ${C.bd}`}}>{i<step?"\u2713":i+1}</div><span style={{fontSize:12,fontWeight:i===step?600:400,color:i<=step?C.txt:C.tm,whiteSpace:"nowrap"}}>{s}</span></div>{i<4&&<div style={{flex:1,height:1,background:i<step?C.primary:C.bd,margin:"0 12px",minWidth:16}}/>}</div>)}</div>

      {step===0&&<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:18}}>
        <div>
          <div style={{background:C.bgW,borderRadius:12,border:`2px dashed ${C.bd}`,padding:32,textAlign:"center",marginBottom:16,cursor:"pointer"}}><Ic n="upload" s={36} c={C.tm}/><p style={{fontSize:14,fontWeight:600,color:C.txt,margin:"14px 0 4px"}}>Glissez-deposez vos fichiers ici</p><p style={{fontSize:12,color:C.tm,margin:0}}>Plusieurs fichiers PDF, DOCX — 25 Mo max chacun</p></div>
          <div style={{background:C.bgW,borderRadius:12,border:`1px solid ${C.bd}`,padding:18}}>
            <h4 style={{fontSize:13,fontWeight:600,color:C.txt,margin:"0 0 12px"}}>Documents dans cette enveloppe (3)</h4>
            {["Contrat_bail_Cocody.pdf","Annexe_etat_des_lieux.pdf","Reglement_copropriete.pdf"].map((f,i)=><div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 12px",borderRadius:8,border:`1px solid ${C.bl}`,marginBottom:6}}>
              <div style={{width:32,height:36,borderRadius:6,background:C.dL,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}><Ic n="doc" s={16} c={C.danger}/></div>
              <div style={{flex:1}}><div style={{fontSize:13,fontWeight:500,color:C.txt}}>{f}</div><div style={{fontSize:11,color:C.tm}}>{[1.2,0.8,2.4][i]} Mo — {[3,2,8][i]} pages</div></div>
              <span style={{fontSize:11,color:C.success,fontWeight:600}}>Pret</span>
              <button style={{background:"none",border:"none",cursor:"pointer"}}><Ic n="x" s={14} c={C.tm}/></button>
            </div>)}
            <button style={{width:"100%",padding:12,borderRadius:8,border:`1.5px dashed ${C.primary}40`,background:C.pL,color:C.primary,fontSize:12,fontWeight:600,cursor:"pointer",marginTop:4}}>+ Ajouter un document</button>
          </div>
        </div>
        <div style={{background:C.bgW,borderRadius:12,border:`1px solid ${C.bd}`,padding:20}}><h4 style={{fontSize:13,fontWeight:600,color:C.txt,margin:"0 0 14px"}}>Apercu</h4><div style={{background:C.bg,borderRadius:8,height:300,display:"flex",alignItems:"center",justifyContent:"center"}}><div style={{textAlign:"center"}}><Ic n="folder" s={44} c={C.tm}/><p style={{color:C.tm,fontSize:12,marginTop:10}}>3 documents dans l'enveloppe</p><div style={{display:"flex",gap:6,justifyContent:"center",marginTop:10}}>{[1,2,3].map(p=><div key={p} style={{width:50,height:65,borderRadius:6,background:C.bgW,border:`1px solid ${C.bd}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,color:C.tm}}>Doc {p}</div>)}</div></div></div></div>
      </div>}

      {step===1&&<div style={{display:"grid",gridTemplateColumns:"1fr 300px",gap:18}}>
        <div style={{background:C.bgW,borderRadius:12,border:`1px solid ${C.bd}`,padding:22}}>
          <h3 style={{fontSize:14,fontWeight:600,color:C.txt,margin:"0 0 14px"}}>Signataires de l'enveloppe</h3>
          <p style={{fontSize:12,color:C.ts,margin:"0 0 14px"}}>Chaque signataire signera les 3 documents de l'enveloppe.</p>
          {[{n:"Bamba Moussa",e:"moussa.b@email.com",o:1},{n:"Traore Ami",e:"ami.traore@sib.ci",o:2}].map((s,i)=><div key={i} style={{display:"flex",alignItems:"center",gap:12,padding:"12px 14px",borderRadius:10,border:`1px solid ${C.bd}`,marginBottom:8}}>
            <Ic n="drag" s={14} c={C.tm}/>
            <div style={{width:26,height:26,borderRadius:8,background:C.primary,color:"#fff",display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:700}}>{s.o}</div>
            <div style={{width:36,height:36,borderRadius:10,background:C.aL,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:700,color:C.accent,fontSize:14}}>{s.n[0]}</div>
            <div style={{flex:1}}><div style={{fontSize:13,fontWeight:600,color:C.txt}}>{s.n}</div><div style={{fontSize:11,color:C.ts}}>{s.e}</div></div>
            <select style={{padding:"5px 8px",borderRadius:6,border:`1px solid ${C.bd}`,fontSize:11,color:C.ts,background:C.bg}}><option>Signataire</option><option>Approbateur</option><option>Copie</option></select>
            <button style={{background:"none",border:"none",cursor:"pointer"}}><Ic n="x" s={14} c={C.tm}/></button>
          </div>)}
          <button style={{width:"100%",padding:12,borderRadius:10,border:`1.5px dashed ${C.primary}40`,background:C.pL,color:C.primary,fontSize:12,fontWeight:600,cursor:"pointer"}}>+ Ajouter un signataire</button>
        </div>
        <div style={{background:C.bgW,borderRadius:12,border:`1px solid ${C.bd}`,padding:18}}>
          <h4 style={{fontSize:13,fontWeight:600,color:C.txt,margin:"0 0 10px"}}>Ordre de signature</h4>
          {["Sequentiel","Parallele"].map((o,i)=><label key={o} style={{display:"flex",alignItems:"center",gap:8,padding:"9px 10px",borderRadius:8,cursor:"pointer",marginBottom:4,border:`1.5px solid ${i===0?C.primary:C.bd}`,background:i===0?C.pL:"transparent"}}><div style={{width:16,height:16,borderRadius:8,border:`2px solid ${i===0?C.primary:C.bd}`,display:"flex",alignItems:"center",justifyContent:"center"}}>{i===0&&<div style={{width:8,height:8,borderRadius:4,background:C.primary}}/>}</div><span style={{fontSize:12,color:C.txt}}>{o}</span></label>)}
          <div style={{marginTop:14,padding:12,background:C.bg,borderRadius:8}}><div style={{fontSize:12,fontWeight:600,color:C.txt,marginBottom:6}}>Resume de l'enveloppe</div><div style={{fontSize:11,color:C.ts}}>3 documents</div><div style={{fontSize:11,color:C.ts}}>2 signataires</div><div style={{fontSize:11,color:C.ts}}>Ordre sequentiel</div></div>
        </div>
      </div>}

      {step===2&&<div style={{display:"grid",gridTemplateColumns:"1fr 210px",gap:18}}>
        <div style={{background:C.bgW,borderRadius:12,border:`1px solid ${C.bd}`,padding:18,position:"relative"}}>
          <div style={{display:"flex",gap:6,marginBottom:12}}>{["Contrat bail","Annexe","Reglement"].map((d,i)=><button key={d} style={{padding:"6px 14px",borderRadius:6,background:i===0?C.primary:"transparent",color:i===0?"#fff":C.ts,border:i===0?"none":`1px solid ${C.bd}`,fontSize:11,fontWeight:600,cursor:"pointer"}}>{d}</button>)}</div>
          <div style={{background:C.bg,borderRadius:8,padding:"20px 28px",minHeight:320,position:"relative"}}>{[...Array(12)].map((_,i)=><div key={i} style={{height:7,background:C.bd,borderRadius:3,marginBottom:8,width:i%4===0?"50%":i%3===0?"35%":"85%"}}/>)}<div style={{position:"absolute",top:110,left:28,width:170,height:46,border:`2px dashed ${C.primary}`,borderRadius:8,background:C.primary+"12",display:"flex",alignItems:"center",justifyContent:"center",gap:5}}><Ic n="pen" s={13} c={C.primary}/><span style={{fontSize:11,fontWeight:600,color:C.primary}}>Signature - Bamba</span></div><div style={{position:"absolute",top:110,left:220,width:80,height:32,border:`2px dashed ${C.accent}`,borderRadius:8,background:C.accent+"12",display:"flex",alignItems:"center",justifyContent:"center"}}><span style={{fontSize:10,fontWeight:600,color:C.accent}}>Date</span></div><div style={{position:"absolute",top:230,left:28,width:170,height:46,border:`2px dashed ${C.purple}`,borderRadius:8,background:C.purple+"12",display:"flex",alignItems:"center",justifyContent:"center",gap:5}}><Ic n="pen" s={13} c={C.purple}/><span style={{fontSize:11,fontWeight:600,color:C.purple}}>Signature - Traore</span></div></div>
        </div>
        <div><div style={{background:C.bgW,borderRadius:12,border:`1px solid ${C.bd}`,padding:14}}><h4 style={{fontSize:12,fontWeight:600,color:C.txt,margin:"0 0 10px"}}>Types de champs</h4>{[{icon:"pen",l:"Signature",c:C.primary},{icon:"clock",l:"Date",c:C.accent},{icon:"user",l:"Initiales",c:C.purple},{icon:"doc",l:"Texte",c:C.success},{icon:"check",l:"Case",c:C.warning}].map((f,j)=><div key={j} style={{display:"flex",alignItems:"center",gap:8,padding:"8px 10px",borderRadius:8,cursor:"grab",marginBottom:5,border:`1px solid ${C.bd}`}}><Ic n={f.icon} s={14} c={f.c}/><span style={{fontSize:12,color:C.txt}}>{f.l}</span></div>)}</div><div style={{background:C.aL,borderRadius:10,padding:12,marginTop:10,fontSize:11,color:C.accent,lineHeight:1.4}}><strong>Astuce :</strong> Placez les champs sur chaque document via les onglets ci-dessus.</div></div>
      </div>}

      {step>=3&&<div style={{maxWidth:660}}>
        <div style={{background:C.bgW,borderRadius:12,border:`1px solid ${C.bd}`,padding:22}}>
          <h3 style={{fontSize:15,fontWeight:600,color:C.txt,margin:"0 0 14px"}}>Recapitulatif de l'enveloppe</h3>
          {[["Documents","Contrat_bail.pdf, Annexe_etat.pdf, Reglement.pdf (3 fichiers)"],["Signataires","Bamba Moussa, Traore Ami (sequentiel)"],["Champs places","4 signatures, 2 dates, 2 initiales"],["Delai d'expiration","7 jours"],["Rappels","Actives (J+3 et J+6)"],["Niveau de signature","Avancee (AES)"]].map(([k,v])=><div key={k} style={{display:"flex",padding:"9px 0",borderBottom:`1px solid ${C.bl}`}}><span style={{width:160,fontSize:12,color:C.ts,fontWeight:500}}>{k}</span><span style={{fontSize:12,color:C.txt}}>{v}</span></div>)}
          <div style={{marginTop:14}}><label style={{fontSize:12,fontWeight:500,color:C.ts,display:"block",marginBottom:5}}>Message personnalise</label><div style={{background:C.bg,border:`1px solid ${C.bd}`,borderRadius:8,padding:12,fontSize:12,color:C.tm,fontStyle:"italic"}}>"Merci de signer ces documents dans les meilleurs delais."</div></div>
        </div>
      </div>}

      <div style={{display:"flex",justifyContent:"space-between",marginTop:22}}><Bt v="outline" onClick={()=>setStep(Math.max(0,step-1))} style={{visibility:step===0?"hidden":"visible"}}>Precedent</Bt>{step<4?<Bt v="primary" onClick={()=>setStep(step+1)}>{step===3?"Envoyer l'enveloppe":"Suivant"}</Bt>:<Bt v="accent" icon="send" onClick={()=>onNav("dashboard")}>Confirmer l'envoi</Bt>}</div>
    </div>
  </div>;
};

