/* ===== MAIN ===== */
const SCREENS={landing:Landing,login:Login,choose_plan:ChoosePlan,register:Register,verify_otp:VerifyOtp,payment:PaymentScreen,payment_success:PaymentSuccess,renewal:Renewal,dashboard:Dashboard,documents:Documents,create:Create,doc_detail:DocDetail,sign_doc:SignDoc,sign_success:SignSuccess,team:Team,templates:Templates,settings:Settings,notifications:Notifications,contacts:Contacts};
const LABELS={landing:"Accueil",login:"Connexion",choose_plan:"Plan",register:"Inscription",verify_otp:"OTP",payment:"Paiement",payment_success:"Confirme",renewal:"Renouveler",dashboard:"Dashboard",documents:"Enveloppes",create:"Nouvelle",doc_detail:"Detail",sign_doc:"Signer",sign_success:"Succes",team:"Equipe",templates:"Modeles",settings:"Params",notifications:"Alertes",contacts:"Contacts"};

export default function App(){
  const[screen,setScreen]=useState("landing");
  const Screen=SCREENS[screen]||Dashboard;
  const showSidebar=!["landing","login","choose_plan","register","verify_otp","payment","payment_success","renewal"].includes(screen);
  return <div style={{display:"flex",flexDirection:"column",height:"100vh",fontFamily:"'DM Sans','Segoe UI',system-ui,sans-serif",background:C.bg,overflow:"hidden"}}>
    <div style={{display:"flex",flex:1,overflow:"hidden"}}>{showSidebar&&<Sidebar active={screen} onNav={setScreen}/>}<Screen onNav={setScreen}/></div>
    <div style={{background:C.bgW,borderTop:`1px solid ${C.bd}`,padding:"4px 14px",display:"flex",justifyContent:"space-between",alignItems:"center",fontSize:10,color:C.tm,flexShrink:0}}>
      <span>SignTrust par Cryptoneo — {Object.keys(SCREENS).length} ecrans</span>
      <div style={{display:"flex",gap:2,flexWrap:"wrap"}}>{Object.entries(LABELS).map(([id,label])=><button key={id} onClick={()=>setScreen(id)} style={{padding:"2px 5px",borderRadius:3,background:screen===id?C.primary:"transparent",color:screen===id?"#fff":C.tm,border:screen===id?"none":`1px solid ${C.bl}`,fontSize:9,cursor:"pointer"}}>{label}</button>)}</div>
    </div>
  </div>;
}
